// To parse this JSON data, do
//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String main;
    String typings;
    Bin bin;
    String author;
    List<Contributor> contributors;
    Repository repository;
    String license;
    List<String> keywords;
    Dependencies dependencies;
    DevDependencies devDependencies;
    Scripts scripts;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.main,
        required this.typings,
        required this.bin,
        required this.author,
        required this.contributors,
        required this.repository,
        required this.license,
        required this.keywords,
        required this.dependencies,
        required this.devDependencies,
        required this.scripts,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        main: json["main"],
        typings: json["typings"],
        bin: Bin.fromJson(json["bin"]),
        author: json["author"],
        contributors: List<Contributor>.from(json["contributors"].map((x) => Contributor.fromJson(x))),
        repository: Repository.fromJson(json["repository"]),
        license: json["license"],
        keywords: List<String>.from(json["keywords"].map((x) => x)),
        dependencies: Dependencies.fromJson(json["dependencies"]),
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
        scripts: Scripts.fromJson(json["scripts"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "main": main,
        "typings": typings,
        "bin": bin.toJson(),
        "author": author,
        "contributors": List<dynamic>.from(contributors.map((x) => x.toJson())),
        "repository": repository.toJson(),
        "license": license,
        "keywords": List<dynamic>.from(keywords.map((x) => x)),
        "dependencies": dependencies.toJson(),
        "devDependencies": devDependencies.toJson(),
        "scripts": scripts.toJson(),
    };
}

class Bin {
    String typescriptJsonSchema;

    Bin({
        required this.typescriptJsonSchema,
    });

    factory Bin.fromJson(Map<String, dynamic> json) => Bin(
        typescriptJsonSchema: json["typescript-json-schema"],
    );

    Map<String, dynamic> toJson() => {
        "typescript-json-schema": typescriptJsonSchema,
    };
}

class Contributor {
    String name;
    String email;
    String? url;

    Contributor({
        required this.name,
        required this.email,
        this.url,
    });

    factory Contributor.fromJson(Map<String, dynamic> json) => Contributor(
        name: json["name"],
        email: json["email"],
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "email": email,
        "url": url,
    };
}

class Dependencies {
    String typesJsonSchema;
    String typesNode;
    String glob;
    String pathEqual;
    String safeStableStringify;
    String tsNode;
    String typescript;
    String yargs;

    Dependencies({
        required this.typesJsonSchema,
        required this.typesNode,
        required this.glob,
        required this.pathEqual,
        required this.safeStableStringify,
        required this.tsNode,
        required this.typescript,
        required this.yargs,
    });

    factory Dependencies.fromJson(Map<String, dynamic> json) => Dependencies(
        typesJsonSchema: json["@types/json-schema"],
        typesNode: json["@types/node"],
        glob: json["glob"],
        pathEqual: json["path-equal"],
        safeStableStringify: json["safe-stable-stringify"],
        tsNode: json["ts-node"],
        typescript: json["typescript"],
        yargs: json["yargs"],
    );

    Map<String, dynamic> toJson() => {
        "@types/json-schema": typesJsonSchema,
        "@types/node": typesNode,
        "glob": glob,
        "path-equal": pathEqual,
        "safe-stable-stringify": safeStableStringify,
        "ts-node": tsNode,
        "typescript": typescript,
        "yargs": yargs,
    };
}

